// Parse the extraction LLM response
const data = $input.first().json;
const inputData = $('Sub-Workflow Input').first().json;
let aiText = '';

try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response from LLM');
} catch (e) {
  return [{ json: { matched: false, error: 'Failed to parse LLM response: ' + e.message, orderLines: [], lineCount: 0 } }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\[[\s\S]*\]/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch (e2) { return [{ json: { matched: false, error: 'Invalid JSON from LLM: ' + e.message, orderLines: [], lineCount: 0 } }]; }
  } else {
    return [{ json: { matched: false, error: 'No JSON array in LLM response', orderLines: [], lineCount: 0 } }];
  }
}

if (!Array.isArray(parsed)) {
  return [{ json: { matched: false, error: 'LLM did not return an array', orderLines: [], lineCount: 0 } }];
}

if (parsed.length === 0) {
  return [{ json: { matched: false, error: 'No order data found in email body', orderLines: [], lineCount: 0 } }];
}

const orderLines = parsed.map(line => ({
  sourceSheet: 'EmailBody',
  sourceRow: null,
  pharmacyId: line.pharmacyId || null,
  pharmacyName: line.pharmacyName || null,
  drugCode: line.drugCode ? String(line.drugCode) : null,
  articleName: line.articleName ? String(line.articleName) : null,
  quantity: Number(line.quantity) || 1,
  unit: line.unit || 'kom',
  discount: line.discount != null ? (Number(line.discount) || 0) : 0,
  notes: line.notes || '',
  parseMethod: 'EMAIL_BODY_AI',
  rawData: line
}));

// Build compact version for verification prompt
const compactLines = orderLines.map(l => ({
  drugCode: l.drugCode,
  articleName: l.articleName,
  quantity: l.quantity,
  unit: l.unit,
  pharmacyId: l.pharmacyId,
  pharmacyName: l.pharmacyName,
  discount: l.discount
}));

// Build verification prompt — LLM2 corrects data but must not change discount
const verifyPrompt = 'You are a data verification assistant for Croatian pharmacy pre-orders.\n\n'
  + 'Re-read the email body below independently and compare against the extracted order lines.\n\n'
  + 'Check for:\n'
  + '- Wrong quantities (must match source exactly)\n'
  + '- Missing order lines (products mentioned but not extracted)\n'
  + '- Wrong drug codes or article names\n'
  + '- Wrong or missing pharmacy info\n'
  + '- Hallucinated lines not in the source email\n'
  + '- Totals/summary rows misinterpreted as order lines\n\n'
  + 'IMPORTANT: Do NOT change the "discount" field in the JSON. Copy it exactly as-is from the extracted lines. The extraction already converted percentage values to whole numbers. Do not "correct" them back.\n\n'
  + 'Return ONLY a raw JSON object (no markdown, no explanation):\n'
  + '{"lines": [...corrected order lines...], "issues": ["description of each change made"], "confidence": <0-100>}\n\n'
  + 'The lines array uses the same schema as below. The issues array describes each correction.\n'
  + 'The confidence field is your 0-100 estimate of extraction accuracy after verification.\n'
  + 'If everything is correct, return the lines unchanged with an empty issues array.\n'
  + 'Write the issues descriptions in Croatian.\n\n'
  + 'Extracted order lines to verify:\n'
  + JSON.stringify(compactLines)
  + '\n\nEmail body to verify against:\n\n'
  + (inputData.emailBodyHtml || '(email body not available)');

return [{
  json: {
    matched: true,
    parseConfidence: 70,
    lineCount: orderLines.length,
    orderLines: orderLines,
    verifyPrompt: verifyPrompt,
    emailBodyHtml: inputData.emailBodyHtml
  }
}];

// Parse verification response — use LLM2 corrections but ALWAYS preserve LLM1 discount
const data = $input.first().json;
const originalResult = $('Parse AI Response').first().json;

if (!originalResult.matched || !originalResult.orderLines || originalResult.orderLines.length === 0) {
  return [{ json: { matched: false, orderLines: [], lineCount: 0, parseMethod: 'EMAIL_BODY_AI' } }];
}

let aiText = '';
try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response');
} catch (e) {
  const result = { ...originalResult };
  delete result.verifyPrompt;
  delete result.emailBodyHtml;
  result.verificationIssues = ['Verification failed: ' + e.message];
  return [{ json: result }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let verification;
try {
  verification = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\{[\s\S]*\}/);
  if (match) {
    try { verification = JSON.parse(match[0]); }
    catch (e2) {
      const result = { ...originalResult };
      delete result.verifyPrompt;
      delete result.emailBodyHtml;
      result.verificationIssues = ['Verification returned invalid JSON: ' + e.message];
      return [{ json: result }];
    }
  } else {
    const result = { ...originalResult };
    delete result.verifyPrompt;
    delete result.emailBodyHtml;
    result.verificationIssues = ['Verification returned invalid JSON: ' + e.message];
    return [{ json: result }];
  }
}

// Support both {lines, issues} and plain array formats
const verifiedLines = Array.isArray(verification.lines) ? verification.lines
  : Array.isArray(verification) ? verification
  : null;
const issues = Array.isArray(verification.issues) ? verification.issues : [];
const confidence = typeof verification.confidence === 'number' ? Math.round(verification.confidence) : 0;

if (!verifiedLines) {
  const result = { ...originalResult };
  delete result.verifyPrompt;
  delete result.emailBodyHtml;
  result.verificationIssues = ['Verification did not return a lines array'];
  return [{ json: result }];
}

const orderLines = verifiedLines.map(line => {
  const drugCode = line.drugCode ? String(line.drugCode) : null;
  const discount = line.discount != null ? (Number(line.discount) || 0) : 0;

  return {
    sourceSheet: 'EmailBody',
    sourceRow: null,
    pharmacyId: line.pharmacyId || null,
    pharmacyName: line.pharmacyName || null,
    drugCode: drugCode,
    articleName: line.articleName ? String(line.articleName) : null,
    quantity: Number(line.quantity) || 1,
    unit: line.unit || 'kom',
    discount: discount,
    notes: '',
    parseMethod: 'EMAIL_BODY_AI_VERIFIED',
    rawData: line
  };
});

const result = { ...originalResult };
delete result.verifyPrompt;
delete result.emailBodyHtml;
result.verificationIssues = issues;
result.parseMethod = 'EMAIL_BODY_AI_VERIFIED';
result.parseConfidence = confidence;
result.orderLines = orderLines;
result.lineCount = orderLines.length;
result.matched = orderLines.length > 0;

return [{ json: result }];
